data.content:
MSTest 3.x+ **does** have these comparison assertions:

```csharp
Assert.IsGreaterThan(lowerBound, actual);   // actual > lowerBound
Assert.IsLessThan(upperBound, actual);      // actual < upperBound
Assert.IsInRange(actual, low, high);        // low <= actual <= high
```

Here's how to apply them to your `ScoreCalculator`:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(3, 7);

        Assert.IsGreaterThan(0.0, result);      // result > 0
        Assert.IsLessThan(100.0, result);       // result < 100
        Assert.IsInRange(result, 0.0, 100.0);   // 0 <= result <= 100
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_ReturnsInRange()
    {
        var result = _calculator.NormalizeScore(45.0, 90.0);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }
}
```

**Key points:**
- `Assert.IsInRange(actual, low, high)` — great for validating normalized/percentage outputs stay in bounds
- `Assert.IsGreaterThan(lowerBound, actual)` — verifies `actual > lowerBound`
- `Assert.IsLessThan(upperBound, actual)` — verifies `actual < upperBound`
- These give much better failure messages than `Assert.IsTrue(result > 0)`

Requires **MSTest 3.x+** (via `MSTest` metapackage or `MSTest.Sdk`).

